SELECT AVG(recommendation_count) AS average_recommendations
FROM (
  SELECT user_id, COUNT(song_id) AS recommendation_count
  FROM recommendations
  GROUP BY user_id
);

SELECT dq.feature_name, dq.quality_score
FROM data_quality dq
WHERE dq.song_id NOT IN (
  SELECT lh.song_id
  FROM listening_history lh
);

SELECT rank
FROM (
    SELECT user_id, RANK() OVER (ORDER BY listened_count DESC) as rank
    FROM (
        SELECT user_id, COUNT(*) as listened_count
        FROM listening_history
        GROUP BY user_id
    )
) AS ranked_users
WHERE user_id = 1;

SELECT T1.user_id
FROM listening_history AS T1
WHERE T1.song_id = (
  SELECT song_id
  FROM data_quality
  WHERE quality_score = (
    SELECT MAX(quality_score)
    FROM data_quality
  )
);

SELECT COUNT(DISTINCT user_id) AS num_users
FROM listening_history
WHERE song_id = (SELECT MAX(song_id) FROM data_provenance);
